import React from 'react';
import { Link } from 'react-router-dom';
import { DevCompanyPicker } from '@linm-soft-org/linm-web-common-components';
import type { DevModuleGroup, DevRouteBadge } from './types';
import styles from './DevPage.module.css';

const BADGE_CLASS: Record<DevRouteBadge, string> = {
  GET: styles.badgeGET,
  FORM: styles.badgeFORM,
  DETAIL: styles.badgeDETAIL,
  REPORT: styles.badgeREPORT,
  MANAGE: styles.badgeMANAGE,
};

const LEGEND: DevRouteBadge[] = ['GET', 'FORM', 'DETAIL', 'REPORT', 'MANAGE'];

export interface DevPageViewProps {
  modules: DevModuleGroup[];
  appName?: string;
}

export const DevPageView: React.FC<DevPageViewProps> = ({ modules, appName }) => {
  const totalRoutes = modules.reduce((s, m) => s + m.routes.length, 0);
  const title = appName ?? import.meta.env.VITE_APP_NAME ?? 'LINM Home';

  return (
    <div className={styles.page}>
      <div className={styles.inner}>
        <header className={styles.header}>
          <div className={styles.titleRow}>
            <h1 className={styles.title}>Dev Navigation</h1>
            <span className={styles.devTag}>DEV ONLY</span>
          </div>
          <p className={styles.subtitle}>
            {title} · {totalRoutes} routes · {modules.length} nhóm · Click để mở trang
            <span className={styles.badgeLegend}>
              {LEGEND.map((b) => (
                <span key={b} className={`${styles.legendTag} ${styles[`legend${b}`]}`}>{b}</span>
              ))}
            </span>
          </p>
        </header>

        <DevCompanyPicker />

        <div className={styles.grid}>
          {modules.map((mod) => (
            <section
              key={mod.prefix}
              className={styles.card}
              style={{ '--module-color': mod.color } as React.CSSProperties}
            >
              <div className={styles.cardHeader}>
                <i className={mod.iconClass} aria-hidden />
                <span>{mod.title}</span>
                <span className={styles.count}>{mod.routes.length}</span>
              </div>
              {mod.routes.map((r, i) => (
                <React.Fragment key={r.url}>
                  <Link to={r.url} className={styles.routeLink}>
                    <span className={styles.routeLabel}>{r.label}</span>
                    <span className={styles.routeMeta}>
                      {r.badge && (
                        <span className={`${styles.routeBadge} ${BADGE_CLASS[r.badge]}`}>{r.badge}</span>
                      )}
                      <span className={styles.routeUrl}>{r.url}</span>
                    </span>
                  </Link>
                  {i < mod.routes.length - 1 && <hr className={styles.divider} />}
                </React.Fragment>
              ))}
            </section>
          ))}
        </div>

        <p className={styles.footer}>
          Chỉ hiển thị khi <code>yarn start:std</code>. Không có trong production build tích hợp root.
        </p>
      </div>
    </div>
  );
};

export default DevPageView;
